// Project dictionary/document blobs from Audacity's
// src/trackedit/tests/data/empty.aup4 at commit
// 908ad0a526e5bfdab68de780e893cebe172d27eb.
export const AUP4_BINARY_XML_ORACLE = Object.freeze({
	dictionaryBase64: '',
	documentBase64: '',
});

export function decodeBase64Bytes(value) {
	return Uint8Array.from(Buffer.from(value, 'base64'));
}
